import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Layout from './components/Layout/Layout';

const SimpleDashboard = () => {
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Simple Dashboard</h1>
          <p className="text-gray-600">Basic React without complex state</p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow p-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Welcome!</h2>
        <p className="text-gray-700">
          If you can see this message, React and Tailwind CSS are working correctly.
        </p>

        <div className="mt-6 p-4 bg-green-50 border border-green-200 rounded-lg">
          <h3 className="text-green-800 font-medium">✅ Success!</h3>
          <p className="text-green-700 mt-2">
            The application is ready to use.
          </p>
        </div>
      </div>
    </div>
  );
};

const SimpleApp = () => {
  return (
    <Router>
      <Layout>
        <Routes>
          <Route path="/" element={<SimpleDashboard />} />
        </Routes>
      </Layout>
    </Router>
  );
};

export default SimpleApp;
